import sailpoint.object.Identity;
import sailpoint.api.IdentityService;
import sailpoint.object.Application;

log.error("primaryAccount--"+primaryAccount);
Message msg=new Message();

Identity identity=context.getObjectById(Identity.class,primaryAccount);
IdentityService identityService = new IdentityService(context);

if(secondaryIdType.equals("ADAdmin")){
Application adApp=context.getObjectByName(Application.class,"ActiveDirectory");
List ADlinks=identityService.getLinks(identity,adApp);

Link adminLink=identityService.getLink(identity,adApp,null);
if(ADlinks!=null @and adApp!=null @and !ADlinks.isEmpty()){

// ProvisioningPlan plan=createADAdminAccount(identity,adApp);
}
else
{
return "Entered Identity doesn't have PrimaryAccount in ActiveDirectory";
}
}



if((secondaryIdType.equals("CloudAdmin")){
Application ldapApp=context.getObjectByName(Application.class,"LDAPApplication");
List ldapLinks=identityService.getLinks(identity,ldapApp);

if(ldapLinks!=null @and ldapApp!=null @and !ldapLinks.isEmpty()){

//ProvisioningPlan plan=createLDAPAdminAccount(identity,ldapApp);
}
else
{
return "Entered Identity doesn't have PrimaryAccount in LDAPApplication";
}
}

return msg;
